import json
from datetime import datetime, timedelta
from typing import Dict, List, Optional, Any

class MarketDataFetcher:
    """Fetches prediction market data from various APIs."""

    def __init__(self, api_key: Optional[str] = None, base_url: str = "https://api.predictionmarkets.com/v1"):
        self.api_key = api_key
        self.base_url = base_url
        self.session = requests.Session()
        if api_key:
            self.session.headers.update({"Authorization": f"Bearer {api_key}"})

    def get_market(self, market_id: str) -> Dict[str, Any]:
        """Fetch details for a specific market."""
        response = self.session.get(f"{self.base_url}/markets/{market_id}")
        response.raise_for_status()
        return response.json()

    def get_markets(self, status: str = "active", limit: int = 50) -> List[Dict]:
        """Fetch list of markets with optional filtering."""
        params = {"status": status, "limit": limit}
        response = self.session.get(f"{self.base_url}/markets", params=params)
        response.raise_for_status()
        return response.json().get("markets", [])

    def get_odds(self, market_id: str) -> Dict[str, float]:
        """Fetch current odds for a market."""
        response = self.session.get(f"{self.base_url}/markets/{market_id}/odds")
        response.raise_for_status()
        return response.json()

    def get_historical_prices(self, market_id: str, days: int = 30) -> List[Dict]:
        """Fetch historical price data for a market."""
        end_date = datetime.now()
        start_date = end_date - timedelta(days=days)
        params = {
            "start": start_date.isoformat(),
            "end": end_date.isoformat(),
            "interval": "1h"
        }
        response = self.session.get(f"{self.base_url}/markets/{market_id}/history", params=params)
        response.raise_for_status()
        return response.json().get("prices", [])

    def get_volume(self, market_id: str) -> Dict[str, Any]:
        """Fetch trading volume for a market."""
        response = self.session.get(f"{self.base_url}/markets/{market_id}/volume")
        response.raise_for_status()
        return response.json()

def create_fetcher(api_key: Optional[str] = None) -> MarketDataFetcher:
    """Factory function to create a MarketDataFetcher instance."""
    return MarketDataFetcher(api_key=api_key)
