{"status": "success", "tool": "read_file", "path": "02_SKILLS/risk_management/risk_models/var_model.py", "content": """"
Value at Risk (VaR) Model
Calculates portfolio VaR using historical simulation method.
"""
import numpy as np
from typing import List, Dict, Optional

class VaRModel:
    def __init__(self, confidence_level: float = 0.95, horizon: int = 1):
        self.confidence_level = confidence_level
        self.horizon = horizon

    def calculate_historical_var(self, returns: np.ndarray) -> float:
        """Calculate VaR using historical simulation."""
        if len(returns) == 0:
            return 0.0
        var = np.percentile(returns, (1 - self.confidence_level) * 100)
        return var * np.sqrt(self.horizon)

    def calculate_parametric_var(self, mean: float, std: float) -> float:
        """Calculate VaR using parametric (variance-covariance) method."""
        from scipy import stats
        z_score = stats.norm.ppf(1 - self.confidence_level)
        return (mean + z_score * std) * np.sqrt(self.horizon)

    def calculate_portfolio_var(self, positions: List[Dict], 
                                 returns_matrix: np.ndarray) -> float:
        """Calculate portfolio-level VaR."""
        weights = np.array([p.get('weight', 0) for p in positions])
        portfolio_returns = returns_matrix @ weights
        return self.calculate_historical_var(portfolio_returns)
